// ============================================================
// PROYECCI?N TOTAL DE AHORRO ? DIRECTO + ADICIONAL
// ============================================================
const params = $('Set | All Params').first().json;
const leadsProyectados = Number(params.leads_interacted_proyectados);
const interactedRaw = $('Interacted Leads Base').all().map(i => i.json);
const todos = items.map(i => i.json);
const baseLeadsSet = new Set(interactedRaw.map(r => Number(r.lead_id)));
const baseLeadsCount = baseLeadsSet.size;
const scale = baseLeadsCount > 0 ? leadsProyectados / baseLeadsCount : 0;
const SEMANAS_POR_MES = 4.33;
const salarioMensualBob = Number(params.salario_mensual_asistente_bob);
const horasSemana = Number(params.horas_semana);
const costoHoraBob = Math.round((salarioMensualBob / (horasSemana * SEMANAS_POR_MES)) * 100) / 100;
function n(v){ const x = Number(v); return Number.isFinite(x) ? x : 0; }
function round(v,d=2){ const m=Math.pow(10,d); return Math.round(n(v)*m)/m; }
function firstLeadKeys(item){ return Object.keys((item.detalle_tecnico?.desglose_por_lead || [])[0] || {}); }
function isBotWorkload(item){ return item.tipo_stats === 'bot_workload'; }
function isLeadRegistration(item){ return item.tipo_stats === 'lead_registration'; }
function isSummaryUpdates(item){ return item.tipo_stats === 'summary_updates'; }
function isPipelineMoves(item){ return item.tipo_stats === 'pipeline_moves'; }
function isInventoryOps(item){ return item.tipo_stats === 'inventory_ops'; }
function isSuggester(item){ return firstLeadKeys(item).includes('modelos_evaluados_total'); }
function isDetails(item){ return firstLeadKeys(item).includes('proyectos_compilados_total'); }
function isScheduler(item){ const keys = firstLeadKeys(item); return keys.includes('total_solicitudes') && !isBotWorkload(item) && !isLeadRegistration(item) && !isSummaryUpdates(item) && !isPipelineMoves(item); }
const components = { lead_registration: todos.find(isLeadRegistration), bot_workload: todos.find(isBotWorkload), suggester: todos.find(isSuggester), details: todos.find(isDetails), scheduler: todos.find(isScheduler), summary_updates: todos.find(isSummaryUpdates), pipeline_moves: todos.find(isPipelineMoves), inventory_ops: todos.find(isInventoryOps) };
const required = ['lead_registration','bot_workload','suggester','details','scheduler','summary_updates','pipeline_moves','inventory_ops'];
const missing = required.filter(k => !components[k]);
if (!baseLeadsCount || missing.length) return [{ json: { tipo_salida: 'error_missing_input_branch_v2', error: 'Faltan ramas para calcular la proyecci?n completa', missing, interacted_rows: baseLeadsCount, received_tipo_stats: todos.map(x => x.tipo_stats || null), received_keys: todos.map(x => firstLeadKeys(x)) } }];
function hoursOf(item, field='horas_ahorradas'){ return n(item?.resumen_ejecutivo?.[field]); }
function bobOfHours(h){ return round(h * costoHoraBob, 2); }
const directKeys = ['lead_registration','bot_workload','suggester','details','scheduler'];
const additionalLeadKeys = ['summary_updates','pipeline_moves'];
const directRealHours = round(directKeys.reduce((s,k)=>s+hoursOf(components[k]),0),2);
const directProjectedHours = round(directRealHours * scale, 2);
const additionalLeadRealHours = round(additionalLeadKeys.reduce((s,k)=>s+hoursOf(components[k]),0),2);
const additionalLeadProjectedHours = round(additionalLeadRealHours * scale, 2);
const inventorySetupHours = hoursOf(components.inventory_ops, 'horas_creacion_inventario');
const inventoryRecurringHours = hoursOf(components.inventory_ops, 'horas_revision_disponibilidad_mes');
const additionalMonthlyProjectedHours = round(additionalLeadProjectedHours + inventoryRecurringHours, 2);
const additionalReferenceTotalHours = round(additionalMonthlyProjectedHours + inventorySetupHours, 2);
const totalMonthlyProjectedHours = round(directProjectedHours + additionalMonthlyProjectedHours, 2);
const totalReferenceWithSetupHours = round(directProjectedHours + additionalReferenceTotalHours, 2);
function compSummary(k){ const item = components[k]; const rawH = hoursOf(item); const isInventory = k === 'inventory_ops'; const projectedH = isInventory ? rawH : rawH * scale; return { componente: k, clasificacion_ahorro: item.clasificacion_ahorro || null, scale_mode: item.scale_mode || (isInventory ? 'inventory_not_lead_scaled' : 'per_lead'), leads_con_uso: item.resumen_ejecutivo?.leads_atendidos ?? null, horas_reales_periodo: round(rawH,2), horas_proyectadas_o_referencia: round(projectedH,2), ahorro_bob_proyectado_o_referencia: bobOfHours(projectedH), resumen_ejecutivo: item.resumen_ejecutivo || {} }; }
const porLead = {};
for (const lead_id of baseLeadsSet) porLead[lead_id] = { lead_id };
for (const [k,item] of Object.entries(components)) {
  for (const r of (item.detalle_tecnico?.desglose_por_lead || [])) {
    const id = Number(r.lead_id); if (!porLead[id]) continue;
    porLead[id]['horas_' + k] = n(r.horas_ahorradas);
    porLead[id]['ahorro_' + k + '_bob'] = n(r.ahorro_equivalente_bob);
  }
}
for (const l of Object.values(porLead)) { l.horas_directas = round(directKeys.reduce((s,k)=>s+n(l['horas_' + k]),0),4); l.horas_adicionales = round(additionalLeadKeys.reduce((s,k)=>s+n(l['horas_' + k]),0),4); }
return [{ json: { tipo_salida: 'projection_total_ahorro_interacted_v2', scope: { base: 'Leads (CTWA/MM/Active) with Bot & Lead Reply', periodo_inicio: params.period_start, periodo_fin: params.period_end, target_user_id: params.target_user_id, leads_interacted_reales_periodo: baseLeadsCount, leads_interacted_proyectados: leadsProyectados, escala_proyeccion_leads: round(scale,4) }, resumen_capas: { ahorro_operativo_directo: { componentes: directKeys, horas_reales_periodo: directRealHours, horas_proyectadas_mes: directProjectedHours, ahorro_proyectado_mes_bob: bobOfHours(directProjectedHours) }, valor_operativo_adicional_automatizado: { componentes_lead_scaled: additionalLeadKeys, horas_lead_scaled_reales_periodo: additionalLeadRealHours, horas_lead_scaled_proyectadas_mes: additionalLeadProjectedHours, horas_revision_disponibilidad_mes: round(inventoryRecurringHours,2), horas_creacion_inventario_setup: round(inventorySetupHours,2), horas_adicionales_recurrentes_mes: additionalMonthlyProjectedHours, valor_adicional_recurrente_mes_bob: bobOfHours(additionalMonthlyProjectedHours), horas_adicionales_referencia_con_setup: additionalReferenceTotalHours, valor_adicional_referencia_con_setup_bob: bobOfHours(additionalReferenceTotalHours) }, total_recurrente_mes: { horas: totalMonthlyProjectedHours, bob: bobOfHours(totalMonthlyProjectedHours) }, total_referencia_con_setup_inventario: { horas: totalReferenceWithSetupHours, bob: bobOfHours(totalReferenceWithSetupHours) } }, resumen_por_componente: Object.fromEntries(required.map(k => [k, compSummary(k)])), detalle_tecnico: { costo_por_hora_asistente_humano_bob: costoHoraBob, supuestos_nuevos: { segundos_por_registro_lead: params.segundos_por_registro_lead, horas_idle_para_interaccion_resumen: params.horas_idle_para_interaccion_resumen, segundos_por_actualizacion_resumen_interaccion: params.segundos_por_actualizacion_resumen_interaccion, segundos_por_movimiento_embudo: params.segundos_por_movimiento_embudo, minutos_por_proyecto_inventario: params.minutos_por_proyecto_inventario, minutos_por_listing_independiente_inventario: params.minutos_por_listing_independiente_inventario, minutos_revision_disponibilidad_proyecto: params.minutos_revision_disponibilidad_proyecto, dias_ciclo_revision_disponibilidad_proyecto: params.dias_ciclo_revision_disponibilidad_proyecto }, desglose_por_lead: Object.values(porLead) } } }];
